import { fromOpenai } from 'instructor';
import { OpenAI } from 'openai';
import { verify } from '@vex/sdk';

import { z } from 'zod';

const IncidentResponse = z.object({
  action: z.enum(['ISOLATE', 'BLOCK', 'ALERT']),
  target: z.string().ip(),
  requires_human_approval: z.literal(true),
  confidence: z.number().min(0.8),
});

const client = fromOpenai(
  verify(new OpenAI(), {
    fallback: 'human_review_required',
  })
);

const response = await client.chat.completions.create({
  model: 'gpt-4o',
  response_model: IncidentResponse,
  messages: [{ role: 'user', content: 'Block C2 server 45.67.89.10' }],
});
// Vex enforces human approval for critical actions
